-- Apply Wagamama nutrition/allergen workbook data and normalize cuisine values.
-- The workbook is authoritative for supplied values; missing nutrition remains {}.
-- Cuisine is stored as jsonb arrays so dishes/restaurants can carry multiple cuisines.

drop view if exists public.dish_catalog;
drop view if exists public.restaurant_catalog;

alter table public.restaurants
  alter column cuisine type jsonb
  using jsonb_build_array(cuisine);

do $legacy_cuisine$
declare
  cuisine_type text;
begin
  select udt_name
  into cuisine_type
  from information_schema.columns
  where table_schema = 'public'
    and table_name = 'dishes'
    and column_name = 'cuisine';

  if cuisine_type in ('text', 'varchar') then
    execute $sql$
      alter table public.dishes
        alter column cuisine type jsonb
        using case
          when cuisine is null or btrim(cuisine) = '' then '[]'::jsonb
          else jsonb_build_array(cuisine)
        end
    $sql$;
  end if;
end
$legacy_cuisine$;

do $import$
declare
  payload jsonb := convert_from(
    decode($payload$

$payload$, 'base64'),
    'UTF8'
  )::jsonb;
  wagamama_id bigint;
  item jsonb;
  target_id bigint;
  next_dish_id bigint;
  price_value numeric;
  base jsonb;
begin
  select id
  into wagamama_id
  from public.restaurants
  where name = 'Wagamama'
    and branch_name = 'Oxford'
  limit 1;

  if wagamama_id is null then
    raise exception 'Wagamama Oxford restaurant was not found';
  end if;

  update public.restaurants
  set cuisine = '["Japanese", "Asian"]'::jsonb
  where id = wagamama_id;

  update public.dishes
  set name = initcap(name)
  where restaurant_id = wagamama_id;

  select coalesce(max(id), 0) + 1
  into next_dish_id
  from public.dishes;

  for item in select value from jsonb_array_elements(payload)
  loop
    price_value := (item->>'price')::numeric;
    select id
    into target_id
    from public.dishes
    where restaurant_id = wagamama_id
      and lower(name) = lower(item->>'name')
    limit 1;

    if target_id is null then
      base := coalesce(item->'base', '{}'::jsonb);

      insert into public.dishes (
        id, restaurant_id, name, price, description, official_description,
        short_description, course, menu_position, meal_occasions, ingredients,
        cooking_methods, serving_style, cultural_origin, historical_notes,
        portion_category, weight_g, volume_ml, piece_count,
        estimated_satiety_score, suitable_for_sharing, people_served,
        nutrition, diets, dietary_flags, allergens, allergen_details,
        sensory_profile, ingredient_profile, recommendation_metadata,
        availability, hidden_search_tokens, official_image_url, visual_metadata,
        derived_features, data_sources, sponsored
      )
      values (
        next_dish_id,
        wagamama_id,
        item->>'name',
        price_value,
        coalesce(base->>'description', ''),
        base->>'official_description',
        base->>'short_description',
        coalesce(base->>'course', 'mains'),
        coalesce((base->>'menu_position')::integer, 0),
        array(select jsonb_array_elements_text(coalesce(base->'meal_occasions', '[]'::jsonb))),
        array(select jsonb_array_elements_text(coalesce(base->'ingredients', '[]'::jsonb))),
        array(select jsonb_array_elements_text(coalesce(base->'cooking_methods', '[]'::jsonb))),
        base->>'serving_style',
        base->>'cultural_origin',
        base->>'historical_notes',
        base->>'portion_category',
        (base->>'weight_g')::numeric,
        (base->>'volume_ml')::numeric,
        (base->>'piece_count')::integer,
        (base->>'estimated_satiety_score')::numeric,
        (base->>'suitable_for_sharing')::boolean,
        (base->>'people_served')::numeric,
        coalesce(item->'nutrition', '{}'::jsonb),
        array(select jsonb_array_elements_text(coalesce(base->'dietary_flags', '[]'::jsonb))),
        array(select jsonb_array_elements_text(coalesce(base->'dietary_flags', '[]'::jsonb))),
        array(select jsonb_array_elements_text(coalesce(item->'allergens', '[]'::jsonb))),
        coalesce(item->'allergen_details', '{}'::jsonb),
        coalesce(base->'sensory_profile', '{}'::jsonb),
        coalesce(base->'ingredient_profile', '{}'::jsonb),
        coalesce(base->'recommendation_metadata', '{}'::jsonb),
        coalesce(base->'availability', '{"currently_available":true}'::jsonb),
        array(select jsonb_array_elements_text(coalesce(base->'hidden_search_tokens', '[]'::jsonb))),
        base->>'official_image_url',
        coalesce(base->'visual_metadata', '{}'::jsonb),
        coalesce(base->'derived_features', '{}'::jsonb),
        coalesce(base->'data_sources', '{}'::jsonb) || coalesce(item->'data_sources_patch', '{}'::jsonb),
        false
      );

      target_id := next_dish_id;
      next_dish_id := next_dish_id + 1;
    else
      update public.dishes
      set name = item->>'name',
          price = price_value,
          nutrition = coalesce(item->'nutrition', '{}'::jsonb),
          allergens = array(select jsonb_array_elements_text(coalesce(item->'allergens', '[]'::jsonb))),
          allergen_details = coalesce(item->'allergen_details', '{}'::jsonb),
          data_sources = coalesce(data_sources, '{}'::jsonb)
            || coalesce(item->'data_sources_patch', '{}'::jsonb)
      where id = target_id;
    end if;

    update public.dishes
    set restaurant = 'Wagamama Oxford',
        area = 'Market Street',
        cuisine = '["Japanese", "Asian"]'::jsonb
    where id = target_id;

    insert into public.dish_price_history (
      dish_id, service_type, price, currency, region, valid_from
    )
    values (
      target_id,
      'eat_in',
      price_value,
      'GBP',
      'Oxford',
      date '2026-07-18'
    )
    on conflict (dish_id, service_type, region, valid_from) do update set
      price = excluded.price,
      currency = excluded.currency;
  end loop;
end
$import$;

create view public.dish_catalog
with (security_barrier = true, security_invoker = false)
as
select
  d.id,
  d.restaurant_id,
  d.name,
  d.price,
  d.description,
  d.official_description,
  d.short_description,
  d.course,
  d.menu_position,
  d.meal_occasions,
  d.ingredients,
  d.cooking_methods,
  d.serving_style,
  d.cultural_origin,
  d.historical_notes,
  d.portion_category,
  d.weight_g,
  d.volume_ml,
  d.piece_count,
  d.estimated_satiety_score,
  d.suitable_for_sharing,
  d.people_served,
  d.nutrition,
  d.diets,
  d.dietary_flags,
  d.allergens,
  d.allergen_details,
  d.sensory_profile,
  d.ingredient_profile,
  d.recommendation_metadata,
  d.availability,
  d.hidden_search_tokens,
  d.official_image_url,
  d.visual_metadata,
  d.derived_features,
  d.data_sources,
  d.sponsored,
  d.created_at as date_added,
  d.updated_at as date_last_updated,
  restaurant.name as restaurant_name,
  restaurant.chain_name,
  restaurant.branch_name,
  restaurant.area,
  restaurant.cuisine,
  restaurant.city,
  restaurant.country_code,
  coalesce(round(rating_stats.score::numeric, 1), 0)::double precision as score,
  coalesce(rating_stats.rating_count, 0)::bigint as rating_count,
  jsonb_build_object(
    'taste', round(rating_stats.taste_score::numeric, 1),
    'value', round(rating_stats.value_score::numeric, 1),
    'presentation', round(rating_stats.presentation_score::numeric, 1),
    'portion', round(rating_stats.portion_score::numeric, 1),
    'repeat_order_rate', round(rating_stats.repeat_order_rate::numeric, 3)
  ) as experience_scores,
  coalesce(photo_stats.photo_count, 0)::bigint as user_photo_count,
  coalesce(signal_stats.save_count, 0)::bigint as save_count,
  coalesce(signal_stats.favourite_count, 0)::bigint as favourite_count,
  coalesce(tag_stats.tag_counts, '{}'::jsonb) as tag_counts,
  coalesce(tag_stats.search_tags, '{}'::text[]) as search_tags,
  coalesce(price_stats.current_prices, '{}'::jsonb) as current_prices,
  coalesce(price_history_stats.price_history, '[]'::jsonb) as price_history,
  coalesce(media_stats.official_media, '[]'::jsonb) as official_media,
  coalesce(relationship_stats.related_dishes, '[]'::jsonb) as related_dishes,
  case
    when (d.nutrition ->> 'calories_kcal') ~ '^[0-9]+([.][0-9]+)?$'
      then case
        when (d.nutrition ->> 'calories_kcal')::numeric > 0
          then round(d.price / (d.nutrition ->> 'calories_kcal')::numeric, 4)
      end
  end as price_per_calorie,
  case
    when (d.nutrition ->> 'protein_g') ~ '^[0-9]+([.][0-9]+)?$'
      then case
        when (d.nutrition ->> 'protein_g')::numeric > 0
          then round(d.price / (d.nutrition ->> 'protein_g')::numeric, 2)
      end
  end as price_per_gram_protein,
  concat_ws(' ',
    d.name,
    restaurant.name,
    restaurant.chain_name,
    restaurant.branch_name,
    restaurant.area,
    restaurant.cuisine::text,
    d.description,
    d.official_description,
    d.short_description,
    d.serving_style,
    d.cultural_origin,
    d.portion_category,
    array_to_string(d.meal_occasions, ' '),
    array_to_string(d.ingredients, ' '),
    array_to_string(d.cooking_methods, ' '),
    array_to_string(d.dietary_flags, ' '),
    array_to_string(d.hidden_search_tokens, ' '),
    d.nutrition::text,
    d.allergen_details::text,
    d.sensory_profile::text,
    d.ingredient_profile::text,
    d.recommendation_metadata::text,
    d.availability::text,
    d.visual_metadata::text,
    d.derived_features::text
  ) as search_metadata_text
from public.dishes d
join public.restaurants restaurant on restaurant.id = d.restaurant_id
left join lateral (
  select
    avg(r.score) as score,
    count(*) as rating_count,
    avg(r.taste_score) as taste_score,
    avg(r.value_score) as value_score,
    avg(r.presentation_score) as presentation_score,
    avg(r.portion_score) as portion_score,
    avg(case when r.would_order_again is true then 1.0 when r.would_order_again is false then 0.0 end) as repeat_order_rate
  from public.ratings r
  where r.dish_id = d.id
) rating_stats on true
left join lateral (
  select count(photo.id) as photo_count
  from public.rating_photos photo
  join public.ratings photo_rating on photo_rating.id = photo.rating_id
  where photo_rating.dish_id = d.id
) photo_stats on true
left join lateral (
  select
    count(*) filter (where signal.saved) as save_count,
    count(*) filter (where signal.favourite) as favourite_count
  from public.dish_user_signals signal
  where signal.dish_id = d.id
) signal_stats on true
left join lateral (
  select
    jsonb_object_agg(initcap(rollup.tag), rollup.total order by rollup.total desc) as tag_counts,
    array_agg(rollup.tag order by rollup.total desc) as search_tags
  from (
    select source.tag, sum(source.total)::bigint as total
    from (
      select lower(trim(crowd.key)) as tag, crowd.value::bigint as total
      from jsonb_each_text(d.crowd_tags) crowd
      union all
      select lower(trim(user_tag.tag)) as tag, count(*)::bigint as total
      from public.ratings user_rating
      cross join lateral unnest(user_rating.tags) as user_tag(tag)
      where user_rating.dish_id = d.id and trim(user_tag.tag) <> ''
      group by lower(trim(user_tag.tag))
    ) source
    group by source.tag
  ) rollup
) tag_stats on true
left join lateral (
  select jsonb_object_agg(latest.service_type, latest.price) as current_prices
  from (
    select distinct on (history.service_type)
      history.service_type,
      history.price
    from public.dish_price_history history
    where history.dish_id = d.id
      and history.valid_from <= current_date
      and (history.valid_to is null or history.valid_to >= current_date)
    order by history.service_type, history.valid_from desc
  ) latest
) price_stats on true
left join lateral (
  select jsonb_agg(
    jsonb_build_object(
      'service_type', history.service_type,
      'price', history.price,
      'currency', history.currency,
      'region', history.region,
      'valid_from', history.valid_from,
      'valid_to', history.valid_to
    ) order by history.valid_from desc, history.service_type
  ) as price_history
  from public.dish_price_history history
  where history.dish_id = d.id
) price_history_stats on true
left join lateral (
  select jsonb_agg(
    jsonb_build_object(
      'id', media.id,
      'url', media.url,
      'alt_text', media.alt_text,
      'source_type', media.source_type,
      'colour_profile', media.colour_profile,
      'plating_style', media.plating_style
    ) order by media.sort_order, media.created_at
  ) as official_media
  from public.dish_media media
  where media.dish_id = d.id
) media_stats on true
left join lateral (
  select jsonb_agg(
    jsonb_build_object(
      'dish_id', relationship.related_dish_id,
      'name', related.name,
      'restaurant_id', related.restaurant_id,
      'relationship_type', relationship.relationship_type,
      'relevance', relationship.relevance,
      'note', relationship.note
    ) order by relationship.relevance desc nulls last, related.name
  ) as related_dishes
  from public.dish_relationships relationship
  join public.dishes related on related.id = relationship.related_dish_id
  where relationship.dish_id = d.id
) relationship_stats on true;



create view public.restaurant_catalog
with (security_barrier = true, security_invoker = false)
as
select
  restaurant.id,
  restaurant.name,
  restaurant.chain_name,
  restaurant.branch_name,
  restaurant.area,
  restaurant.cuisine,
  restaurant.latitude,
  restaurant.longitude,
  restaurant.city,
  restaurant.country_code,
  restaurant.delivery_radius_km,
  restaurant.description,
  restaurant.created_at,
  restaurant.updated_at,
  coalesce(round(avg(rating.score)::numeric, 1), 0)::double precision as score,
  count(rating.id)::bigint as rating_count
from public.restaurants restaurant
left join public.dishes dish on dish.restaurant_id = restaurant.id
left join public.ratings rating on rating.dish_id = dish.id
group by restaurant.id;



grant select on public.dish_catalog, public.restaurant_catalog to anon, authenticated;

